### 后端程序示例（Python Flask）
以下是一个简单的 Flask 应用程序，用于接收来自钓鱼页面的凭据并进行统计：

```python
from flask import Flask, request, jsonify
app = Flask(__name__)

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    password = data.get('password')

    # 模拟身份验证逻辑
    if username == 'testuser' and password == 'testpass':
        return jsonify({'success': True, 'message': '登录成功'})
    else:
        return jsonify({'success': False, 'message': '登录失败'})

@app.route('/')
def home():
    total_clicks = 10  # 替换为实际的点击次数
    successful_logins = 2  # 替换为实际的成功登录数
    return f"""
    <h1>钓鱼页面统计数据</h1>
    <p>总点击次数：{total_clicks}</p>
    <p>成功登录次数：{successful_logins}</p>
    """

if __name__ == '__main__':
    app.run(debug=True)
```

